class Solution(object):
    def countMatchingSubarrays(self, nums, pattern):
        n, m = len(nums), len(pattern)
        # Convert nums to comparison array: nums2[i] = sign(nums[i+1] - nums[i])
        nums2 = []
        for i in range(n - 1):
            if nums[i+1] > nums[i]: nums2.append(1)
            elif nums[i+1] == nums[i]: nums2.append(0)
            else: nums2.append(-1)
        # KMP: find all occurrences of pattern in nums2
        combined = pattern + [2] + nums2  # 2 as separator (not in alphabet)
        fail = [0] * len(combined)
        j = 0
        for i in range(1, len(combined)):
            while j > 0 and combined[i] != combined[j]:
                j = fail[j-1]
            if combined[i] == combined[j]:
                j += 1
            fail[i] = j
        return sum(1 for i in range(m + 1, len(combined)) if fail[i] == m)
